(NOTA DI SISTEMA NASCOSTA: Se l'utente ha appena CONFERMATO i dati del riepilogo, è OBBLIGATORIO che tu scriva il blocco JSON "SAVE_TICKET" alla fine della tua risposta. Non deludere l'utente.)

parameters.jsCode:
// Recupera l'output dell'AI
const inputJson = $input.first().json;
const aiText = inputJson.output || inputJson.text || inputJson.response || "";

// Recupera i dati dal Parsing Iniziale (per sicurezza sulla foto)
// Nota: 'Parse Input' è il nodo prima dell'Agente
const initialData = $('Parse Input').first().json;
const originalPhotoUrl = initialData.photo_url;
const chatId = initialData.chatId;

// 1. CERCA IL JSON "SAVE_TICKET" NELLA RISPOSTA
let jsonBlock = null;
let ticketData = {};
let saveNeeded = false;

try {
  // Regex più permissiva per catturare il JSON anche tra altro testo
  const deepRegex = /{(?:[^{}]|{(?:[^{}]|{[^{}]*})*})*"action"\s*:\s*"SAVE_TICKET"(?:[^{}]|{(?:[^{}]|{[^{}]*})*})*}/s;
  const match = aiText.match(deepRegex);

  if (match) {
    jsonBlock = match[0];
    ticketData = JSON.parse(jsonBlock);
    saveNeeded = true;
  }
} catch (e) {
  console.log("Errore parsing JSON AI: " + e.message);
}

// 2. PULISCI LA RISPOSTA PER L'UTENTE
// Rimuove il blocco JSON per non mostrarlo in chat
let cleanResponse = aiText;
if (jsonBlock) {
  cleanResponse = aiText.replace(jsonBlock, '').replace(/```json/g, '').replace(/```/g, '').trim();
}

// 3. LOGICA FOTO ROBUSTA
// Se l'AI non ha passato la foto nel JSON, usiamo quella originale estratta all'inizio
const finalPhotoUrl = ticketData.photo_url || originalPhotoUrl || null;

// 4. RITORNO DATI UNIFICATI
return {
  json: {
    ...ticketData,                // Dati estratti dal JSON dell'AI (se presenti)
    photo_url: finalPhotoUrl,     // URL foto garantito
    text_response: cleanResponse, // Testo pulito per l'utente
    save_needed: saveNeeded,      // Flag per attivare il salvataggio
    chat_session_id: chatId       // ID sessione mantenuto
  }
};

// Recupera il body e la chatId dal Webhook
const body = $input.first().json.body;
let message = body.message || "";
let photoUrl = body.photo_url || null;

// LOGICA ESTRAZIONE FOTO DAL TESTO
// Alcuni client mandano la foto come testo: [UTENTE HA CARICATO UNA FOTO: url]
const tagRegex = /\[UTENTE HA CARICATO UNA FOTO:\s*(.*?)\]/;
const match = message.match(tagRegex);

if (match) {
  // Trovato tag foto! Estraiamo l'URL e puliamo il messaggio
  photoUrl = match[1];
  message = message.replace(tagRegex, '').trim();
}

// Ritorniamo i dati puliti pronti per l'AI
return {
  json: {
    chatId: body.chatId,
    message: message,
    photo_url: photoUrl
  }
};
